mapper.select:
SELECT A.REV_NUM , A.PEN_ID , A.USER_ID , C.USER_NAME , A.USER_TYPE , A.REV_TITLE , A.REV_CONTENT , A.REV_STAR , A.REV_DATE , A.REPLY , A.ANS_CONTENT , A.ANS_DATE , B.IMAGE , P.PEN_NAME FROM REVIEW A LEFT OUTER JOIN ( SELECT REV_NUM, group_concat(REV_IMAGE SEPARATOR ',') IMAGE FROM REVIEW_ATTACH GROUP BY REV_NUM) B ON A.REV_NUM = B.REV_NUM JOIN MEMBER C ON A.USER_ID = C.USER_ID AND A.USER_TYPE = C.USER_TYPE JOIN PENSION P ON A.PEN_ID = P.PEN_ID WHERE 1=1
AND A.PEN_ID = #{pen_id}
ORDER BY A.REV_NUM DESC
LIMIT ${index}, ${amount};

mapper.insert:
	INSERT INTO REVIEW
	     ( REV_NUM
	     , PEN_ID
	     , USER_ID
	     , USER_TYPE
	     , REV_TITLE
	     , REV_CONTENT
	     , REV_STAR
	     , REV_DATE
	     , REPLY
	     , ANS_CONTENT
	     , ANS_DATE)
  VALUES ( #{rev_num}
         , #{pen_id}
         , #{user_id}
         , #{user_type}
         , #{rev_title}
         , #{rev_content}
         , #{rev_star}
         , #{rev_date}
         , #{reply}
         , #{ans_content}
         , #{ans_date})
